package com.example.commentapp.service;

import com.example.commentapp.model.Comment;
import org.springframework.stereotype.Service;

import java.time.LocalDateTime;
import java.util.ArrayList;
import java.util.List;

@Service
public class CommentService {

    public List<Comment> getAllComments() {
        List<Comment> comments = new ArrayList<>();
        comments.add(new Comment(1L, "Alice", "This is the <b>first</b> comment. It has some <i>HTML</i> formatting.", LocalDateTime.now().minusDays(2)));
        comments.add(new Comment(2L, "Bob", "Another comment with a <p>paragraph</p> and a <a href='#'>link</a>.", LocalDateTime.now().minusHours(5)));
        comments.add(new Comment(3L, "Charlie", "Just a plain text comment.", LocalDateTime.now().minusMinutes(30)));
        return comments;
    }
}
package com.example.commentapp.controller;

import com.example.commentapp.model.Comment;
import com.example.commentapp.service.CommentService;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.stereotype.Controller;
import org.springframework.ui.Model;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.RequestMapping;

import java.util.List;

@Controller
@RequestMapping("/comments")
public class CommentController {

    private final CommentService commentService;

    @Autowired
    public CommentController(CommentService commentService) {
        this.commentService = commentService;
    }

    @GetMapping
    public String viewComments(Model model) {
        List<Comment> comments = commentService.getAllComments();
        model.addAttribute("comments", comments);
        return "comments";
    }
}
package com.example.commentapp.config;

import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.ComponentScan;
import org.springframework.context.annotation.Configuration;
import org.springframework.web.servlet.config.annotation.EnableWebMvc;
import org.springframework.web.servlet.config.annotation.WebMvcConfigurer;
import org.springframework.web.servlet.view.InternalResourceViewResolver;

@Configuration
@EnableWebMvc
@ComponentScan(basePackages = "com.example.commentapp")
public class WebConfig implements WebMvcConfigurer {

    @Bean
    public InternalResourceViewResolver viewResolver() {
        InternalResourceViewResolver resolver = new InternalResourceViewResolver();
        resolver.setPrefix("/WEB-INF/views/");
        resolver.setSuffix(".jsp");
        return resolver;
    }
}
package com.example.commentapp.config;

